const phone = $input.first().json.telefone || "";

// remove tudo que não for número
const cleaned = phone.replace(/\D/g, "");

// adiciona 55 na frente
const formatted = `55${cleaned}`;

return [
  {
    json: {
      phone: formatted
    }
  }
];

// --- CONFIGURAÇÃO ---
const NOME_NO_WEBHOOK = "Webhook - Cria Workflow"; 

// --- 1. RECUPERAÇÃO DOS DADOS ---
let dadosDashboard;
try {
    const webhookItem = $(NOME_NO_WEBHOOK).first();
    dadosDashboard = webhookItem.json.body || webhookItem.json;
} catch (e) {
    throw new Error(`❌ Erro: Não encontrei o nó '${NOME_NO_WEBHOOK}'.`);
}

if (!dadosDashboard || !dadosDashboard.agent_ia_config) {
    throw new Error("❌ O JSON do Webhook não contém 'config_agente_ia'.");
}

if (items.length === 0 || !items[0].json) {
    throw new Error("❌ O Template do fluxo não chegou.");
}
const templateData = items[0].json;


// --- 2. TRATAMENTO DO WEBHOOK PATH ---
const fullUrl = dadosDashboard.whatsapp_instance.url_webhook;
const cleanUrl = fullUrl.replace(/\/$/, ""); 
const novoPathWebhook = cleanUrl.substring(cleanUrl.lastIndexOf('/') + 1);


// --- 3. PREPARAÇÃO DO NOVO FLUXO ---
const novoWorkflow = {
  nodes: templateData.nodes,
  connections: templateData.connections,
  settings: templateData.settings,
  meta: templateData.meta,
  tags: [] 
};

let workflowString = JSON.stringify(novoWorkflow);


// --- 4. SUBSTITUIÇÕES DO AGENTE ---
const mapAgente = {
  "[NOME_AGENT]": dadosDashboard.agent_ia_config.nome_agente,
  "[PERSONALIDADE]": dadosDashboard.agent_ia_config.personality,
  "[MENSAGEM_SAUDACAO]": dadosDashboard.agent_ia_config.mensagem_boas_vindas,
  "[MENSAGEM_FINALIZACAO]": dadosDashboard.agent_ia_config.mensagem_encerramento,
  "[PERGUNTAS_QUALIFICACAO]": (dadosDashboard.agent_ia_config.perguntas_qualificacao || []).map(q => `- ${q}`).join('\\n'),
};

for (const [key, value] of Object.entries(mapAgente)) {
  workflowString = workflowString.split(key).join(value || "");
}


// --- 5. SUBSTITUIÇÕES TÉCNICAS ---
workflowString = workflowString.replace(
  /"path":\s*"atendimento"/g, 
  `"path": "${novoPathWebhook}"`
);

const tokenTemplateHttp = "51327654-9c82-4456-a7fb-d5a73177b01b"; 
const tokenTemplateBody = "283e8ad3-231b-42aa-ba1e-b8af2b57ecc4";

workflowString = workflowString.split(tokenTemplateHttp).join(dadosDashboard.whatsapp_instance.token);
workflowString = workflowString.split(tokenTemplateBody).join(dadosDashboard.whatsapp_instance.token);

workflowString = workflowString.replace(
  /"instanceName":\s*"atendimento"/g, 
  `"instanceName": "${dadosDashboard.whatsapp_instance.nome_instancia}"`
).replace(
  /"instanceName":\s*"nova"/g, 
  `"instanceName": "${dadosDashboard.whatsapp_instance.nome_instancia}"`
);


// --- 6. FINALIZAÇÃO ---
const finalWorkflow = JSON.parse(workflowString);

// 🚀 AGORA O NAME VEM DO SLUG EXATAMENTE COMO ESTÁ NO PAYLOAD
finalWorkflow.name = dadosDashboard.organization.identificador;

delete finalWorkflow.id;
finalWorkflow.active = true;

return {
  json: finalWorkflow
};

